'use client'

import { useFRMXStore } from '@/store'
import type { ViewMode, ToolMode } from '@/store'

const VIEW_MODES: { mode: ViewMode; label: string; icon: string }[] = [
  { mode: 'plan', label: 'Plan', icon: '▣' },
  { mode: 'elevation', label: 'Elevation', icon: '▤' },
  { mode: '3d', label: '3D', icon: '◇' },
]

const TOOLS: { mode: ToolMode; label: string; icon: string }[] = [
  { mode: 'select', label: 'Select', icon: '↖' },
  { mode: 'pan', label: 'Pan', icon: '✋' },
  { mode: 'draw-wall', label: 'Draw Wall', icon: '╱' },
  { mode: 'add-opening', label: 'Add Opening', icon: '▭' },
  { mode: 'edit-panel', label: 'Edit Panel', icon: '✎' },
]

export default function Toolbar() {
  const { viewMode, toolMode, setViewMode, setToolMode, project, undo, redo, canUndo, canRedo } = useFRMXStore()

  return (
    <div className="flex items-center gap-2 px-4 py-2 bg-gray-100 border-b border-gray-300">
      <span className="font-bold text-sm mr-4">FRMX</span>

      {/* View modes */}
      <div className="flex gap-1 mr-4">
        {VIEW_MODES.map(({ mode, label, icon }) => (
          <button
            key={mode}
            onClick={() => setViewMode(mode)}
            className={`px-3 py-1.5 text-xs rounded ${viewMode === mode ? 'bg-blue-600 text-white' : 'bg-white border border-gray-300 hover:bg-gray-50'}`}
          >
            <span className="mr-1">{icon}</span>{label}
          </button>
        ))}
      </div>

      {/* Tool modes */}
      <div className="flex gap-1 mr-4">
        {TOOLS.map(({ mode, label, icon }) => (
          <button
            key={mode}
            onClick={() => setToolMode(mode)}
            className={`px-3 py-1.5 text-xs rounded ${toolMode === mode ? 'bg-blue-600 text-white' : 'bg-white border border-gray-300 hover:bg-gray-50'}`}
          >
            <span className="mr-1">{icon}</span>{label}
          </button>
        ))}
      </div>

      {/* Separator */}
      <div className="w-px h-6 bg-gray-300 mx-2" />

      {/* Undo/Redo */}
      <button
        onClick={undo}
        disabled={!canUndo()}
        className="px-3 py-1.5 text-xs rounded bg-white border border-gray-300 hover:bg-gray-50 disabled:opacity-40"
      >↩ Undo</button>
      <button
        onClick={redo}
        disabled={!canRedo()}
        className="px-3 py-1.5 text-xs rounded bg-white border border-gray-300 hover:bg-gray-50 disabled:opacity-40"
      >↪ Redo</button>

      {/* Project name */}
      <div className="ml-auto text-xs text-gray-600">
        {project.name}
      </div>
    </div>
  )
}